        }

        int mid = (start + end) / 2;
        if (num[start] < num[mid]) {
            return binFindMin(num, mid + 1, end);
        } else if (num[start] > num[mid]) {
            return binFindMin(num, start, mid);
        } else {
            if (start == mid && num[start] > num[end]) {
                return num[end];
            }
            return binFindMin(num, start + 1, end);
        }
    }
}
