            for (int j = i; j < s.length(); j += (nRows - 1) * 2) {
                sb.append(s.charAt(j));
                if (j + (nRows - i - 1) * 2 < s.length()) {
                    sb.append(s.charAt(j + (nRows - i - 1) * 2));
                }
            }
        }
        for (int i = nRows - 1; i < s.length(); i += (nRows - 1) * 2) {
            sb.append(s.charAt(i));
        }

        return sb.toString();
    }
}
